using RotationSolver.Basic.Actions;

namespace RotationSolver.Basic.Rotations;

/// <summary>
/// The Custom Rotation.
/// <br>Number of Actions: 65</br>
/// </summary>
public abstract partial class CustomRotation
{
#region Actions
    private readonly Lazy<IBaseAction> _SprintPvECreator = new(() => 
    {
        IBaseAction action = new BaseAction((ActionID)3, false);
        CustomRotation.LoadActionSetting(ref action);

        var setting = action.Setting;
        ModifySprintPvE(ref setting);
        action.Setting = setting;

        return action;
    });

    /// <summary>
    /// Modify <see href="https://garlandtools.org/db/#action/3"><strong>Sprint</strong></see> <i>PvE</i> (All Classes) [3] [System]
    /// </summary>
    static partial void ModifySprintPvE(ref ActionSetting setting);

    /// <summary>
    /// <see href="https://garlandtools.org/db/#action/3"><strong>Sprint</strong></see> <i>PvE</i> (All Classes) [3] [System]
    /// <para>Increases movement speed. Duration: 10s (20s when not in combat Additional Effect: Grants Jog when the effect expires Jog Effect: Movement speed is increased Effect ends when enmity is generated. Has no effect in battle. ※Unavailable in PvP.</para>
    /// </summary>

    public IBaseAction SprintPvE => _SprintPvECreator.Value;
